first_mes:
深夜的图书馆，停电了。

<div id="arc-panel" style="margin-top:16px; background:linear-gradient(135deg,#1a1a2e,#16213e); border:1px solid #e94560; border-radius:12px; padding:16px; font-family:sans-serif; color:#eee; max-width:360px;">
  <div style="font-size:13px; color:#e94560; letter-spacing:2px; margin-bottom:8px;">▸ 故事大纲</div>
  <div id="scene-title" style="font-size:15px; font-weight:bold; margin-bottom:4px;">第一幕：困境</div>
  <div id="scene-desc" style="font-size:12px; color:#aaa; margin-bottom:12px;">两人被困在停电的图书馆，外面的门被锁死，需要找到另一条出路。</div>
  <div style="font-size:11px; color:#e94560; margin-bottom:6px;">BEATS</div>
  <div id="beats-list" style="font-size:12px; color:#ccc; margin-bottom:14px; line-height:1.8;">
    <div id="beat-0">◻ 发现被困，确认出口全部锁死</div>
    <div id="beat-1">◻ 找到手电筒，开始探索书架深处</div>
    <div id="beat-2">◻ 发现一扇隐藏的小门</div>
  </div>
  <div style="display:flex; gap:8px; flex-wrap:wrap;">
    <button onclick="markBeat()" style="flex:1; background:#e94560; border:none; color:#fff; padding:7px 10px; border-radius:8px; font-size:12px; cursor:pointer;">✓ 完成当前Beat</button>
    <button onclick="nextScene()" style="flex:1; background:#0f3460; border:1px solid #e94560; color:#e94560; padding:7px 10px; border-radius:8px; font-size:12px; cursor:pointer;">▶ 进入下一幕</button>
  </div>
  <div id="progress-bar" style="margin-top:12px; height:4px; background:#0f3460; border-radius:4px;">
    <div id="progress-fill" style="height:4px; background:#e94560; border-radius:4px; width:0%; transition:width 0.4s;"></div>
  </div>
  <div id="progress-text" style="font-size:11px; color:#666; margin-top:4px; text-align:right;">0/3 beats · 第1幕/共3幕</div>
</div>

<script>
const SCENES = [
  {
    title: "第一幕：困境",
    desc: "两人被困在停电的图书馆，外面的门被锁死，需要找到另一条出路。",
    beats: ["发现被困，确认出口全部锁死", "找到手电筒，开始探索书架深处", "发现一扇隐藏的小门"],
    systemPrompt: "【当前场景：第一幕·困境】两人刚刚发现图书馆停电且被锁死。氛围压抑、紧张，充满未知威胁。请专注于建立恐惧感和两人之间的微妙关系，节奏宜缓，细节丰富。"
  },
  {
    title: "第二幕：探索",
    desc: "穿过隐藏的小门，进入图书馆地下室，发现了意想不到的秘密。",
    beats: ["进入地下室，发现异常陈设", "找到关于这栋建筑的神秘档案", "意识到被困并非偶然"],
    systemPrompt: "【当前场景：第二幕·探索】两人进入地下室，正在发现这栋建筑隐藏的秘密。请推进悬疑感，让两人面临更多未知，彼此之间的信任开始被考验。"
  },
  {
    title: "第三幕：抉择",
    desc: "找到了出路，但离开意味着放弃这里发现的秘密，两人必须做出选择。",
    beats: ["发现真正的出口", "秘密完全揭露", "两人做出最终抉择"],
    systemPrompt: "【当前场景：第三幕·抉择】出路已经找到，但秘密也随之揭露。请推动故事走向高潮，两人必须面对这个秘密并做出选择，给这段经历一个有力的收尾。"
  }
];

let currentScene = tavo.get('arc_scene') || 0;
let currentBeat = tavo.get('arc_beat') || 0;

async function injectScenePrompt(sceneIndex) {
  const scene = SCENES[sceneIndex];
  const prevMsgId = tavo.get('arc_msg_id');
  if (prevMsgId) { await tavo.message.delete(prevMsgId); }
  const msgId = await tavo.message.append({
    role: 'system',
    content: scene.systemPrompt,
    hidden: true,
  });
  tavo.set('arc_msg_id', msgId);
}

function renderPanel() {
  const scene = SCENES[currentScene];
  document.getElementById('scene-title').textContent = scene.title;
  document.getElementById('scene-desc').textContent = scene.desc;
  const beatsList = document.getElementById('beats-list');
  beatsList.innerHTML = scene.beats.map((b, i) =>
    `<div style="color:${i < currentBeat ? '#e94560' : '#ccc'}">${i < currentBeat ? '✓' : '◻'} ${b}</div>`
  ).join('');
  const pct = scene.beats.length > 0 ? (currentBeat / scene.beats.length * 100) : 0;
  document.getElementById('progress-fill').style.width = pct + '%';
  document.getElementById('progress-text').textContent =
    `${currentBeat}/${scene.beats.length} beats · 第${currentScene+1}幕/共${SCENES.length}幕`;
}

async function markBeat() {
  const scene = SCENES[currentScene];
  if (currentBeat >= scene.beats.length) { tavo.utils.toast('本幕所有Beat已完成，请进入下一幕'); return; }
  currentBeat++;
  tavo.set('arc_beat', currentBeat);
  renderPanel();
  tavo.utils.toast(`✓ Beat完成 ${currentBeat}/${scene.beats.length}`);
}

async function nextScene() {
  if (currentScene >= SCENES.length - 1) { tavo.utils.toast('🎬 故事已结束'); return; }
  currentScene++;
  currentBeat = 0;
  tavo.set('arc_scene', currentScene);
  tavo.set('arc_beat', 0);
  await injectScenePrompt(currentScene);
  renderPanel();
  tavo.utils.toast(`▶ 进入${SCENES[currentScene].title}`);
}

(async () => {
  await injectScenePrompt(currentScene);
  renderPanel();
})();
</script>
